    /** Full update; bumps the catcher's version. Empty providerApiKey keeps the current key. */
    updateCatcher(id: string, req: CatcherWriteRequest): Promise<CatcherDto>;
    setEnabled(id: string, enabled: boolean): Promise<CatcherDto>;
    deleteCatcher(id: string): Promise<void>;
    /** Queue a consolidation (dedupe/merge/prune) run for one bank. Returns immediately (202). */
    consolidate(id: string): Promise<void>;
    /** List recorded consolidation runs for one bank, newest first. */
    listConsolidationRuns(catcherId: string, page?: number, pageSize?: number): Promise<ConsolidationRunDto[]>;
    /** Queue a re-embed: re-projects BM25 facts whose vectors are missing from Qdrant. Returns immediately (202). */
    reembed(id: string): Promise<void>;
    listFacts(catcherId: string, opts?: {
        access?: string;
        search?: string;
        page?: number;
        pageSize?: number;
    }): Promise<FactPage>;
    updateFact(id: string, content: string): Promise<FactDto>;
    deleteFact(id: string): Promise<void>;
    listTemplates(): Promise<TemplateDto[]>;
    getTemplate(id: string): Promise<TemplateDetail>;
    listTemplateVersions(id: string): Promise<TemplateVersionDto[]>;
    deleteTemplate(id: string): Promise<void>;
    /** Save a bank's current config as a new template (v1) and pin the bank to it. */
